settings.custom_css:
/*animasi zoom in awal buka link*/

.info_modalx{
  padding: 10px;
  animation: zoom-in 3s ease-out;
}

/* wdp dear to */
.wdp-dear{
    margin-top: 50px !important;
    animation: zoom-in 4s ease-out;
}

.wdp-name{
    animation: zoom-in 7s ease-out;
}

@keyframes zoom-in {
  0% {
    transform: scale(0);
  }
  100% {
    transform: scale(1);
  }
}
/* animasi foto mempelai */
selector .elementor-image {
    margin-bottom: -30px;
    animation: grow 5s ease-in infinite;
}
@keyframes grow {
  0% {
    transform: scale(1);
  }
    50% {
    transform: scale(1.1);
  }
  100% {
      transform: scale(1);
  }
}
/*custom posisi teks nama mempelai -boleh dihapus */
.wdp-mempelai{
    margin: 60px 0px 10px 0;
    animation: zoom-in 5s ease-out;
}


.wdp-text{
    padding-right: 10px;
    padding-left: 10px;
}
.wdp-name{
    padding: 0 5px 0 5px;
    animation: zoom-in 7s ease-out;
}

@keyframes zoom-in {
  0% {
    transform: scale(0);
  }
  100% {
    transform: scale(1);
  }
}
/*penambahan text di atas foto mempelai*/
selector .elementor-image::before {
      content: "Undangan Pernikahan";
      color: #484729;
      white-space: pre;
      display: block;
      font-size: 32px;
  font-family: 'Crimson Pro';
  font-weight: normal;
  margin: 0 0 150px 0;
    }
/*penambahan text di bawah tombol buka undangan. jenis dan ukuran font silakan kreasikan sesuai kebutuhan*/


/*slide to top */
.removeModals {
    transform: translateY(-200%);
    transition: 4s ease-in-out;
}

selector{
/* From https://css.glass */
background: rgba(255, 255, 255, 0.36);
border-radius: 16px;
box-shadow: 0 4px 30px rgba(0, 0, 0, 0.1);
backdrop-filter: blur(8.5px);
-webkit-backdrop-filter: blur(8.5px);
}

/* Kotak Konfirmasi Kehadiran */
.cui_comment_count_card {
border-radius: 8px;
text-align: center;
display: flex;
flex-flow: column;
align-items: center;
justify-content: center;
border: 1px solid;
padding: 1px ;
color: #fff;
}
.cui_comment_count_card_row {
display: grid;
grid-template-columns: repeat(3,minmax(0,1fr));
gap: -10rem;
}

/* Font Angka Konfirmasi Kehadiran */
.cui_comment_count_card span:first-child {
font-family: alice !important;
font-size: 20px;
font-weight: bolder;
}

/* Font Konfirmasi Kehadiran */
.cui_comment_count_card{
font-family: alice !important;
font-size: 12px;
}

/*Warna Box*/
.cui_comment_count_card.cui_card-hadir {
background-color: #D58E69;
}

.cui_comment_count_card.cui_card-tidak_hadir {
background-color: #958685;
}

.cui_comment_count_card.cui_card-masih_ragu {
background-color: #ABADA4;
}

